import React, { useState, useEffect } from 'react';
import { saveChat, getChatHistory } from '../services/api';
import { auth } from '../services/firebase';

function ChatInterface({ userId }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');

  useEffect(() => {
    if (userId) {
      // Load chat history
      getChatHistory(userId).then(chats => {
        setMessages(chats);
      });
    }
  }, [userId]);

  const sendMessage = async () => {
    if (!input.trim()) return;

    const newMessage = { text: input, sender: 'user', timestamp: new Date() };
    setMessages(prev => [...prev, newMessage]);
    setInput('');

    // Save user message
    if (userId) {
      await saveChat(userId, input, 'user');
    }

    // Here you would typically send the message to the backend and get a response
    // For simplicity, we'll simulate a response
    setTimeout(() => {
      const botResponse = { text: 'This is a simulated response.', sender: 'bot', timestamp: new Date() };
      setMessages(prev => [...prev, botResponse]);

      // Save bot response
      if (userId) {
        saveChat(userId, botResponse.text, 'bot');
      }
    }, 1000);
  };

  return (
    <div className="chat-container">
      <div className="messages">
        {messages.map((msg, i) => (
          <div key={i} className={`message ${msg.sender}`}>
            {msg.text}
          </div>
        ))}
      </div>
      <div className="input-area">
        <input 
          value={input} 
          onChange={(e) => setInput(e.target.value)} 
          placeholder="Ask about your career..."
          onKeyPress={(e) => e.key === 'Enter' && sendMessage()}
        />
        <button onClick={sendMessage}>Send</button>
      </div>
    </div>
  );
}

export default ChatInterface;
